// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.hypergraph;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Optional;
import java.util.Set;

import org.junit.jupiter.api.Test;

class HypergraphOptimizerTest {

	@Test
	void emptyGraphYieldsNoPlan() {
		assertTrue(HypergraphOptimizer.bestPlan(new PlanHypergraph(), CostModel.DEFAULT).isEmpty());
	}

	@Test
	void singleNodeYieldsItsScan() {
		PlanHypergraph planGraph = new PlanHypergraph();
		planGraph.addNode("A", 42);
		Optional<JoinPlan> best = HypergraphOptimizer.bestPlan(planGraph, CostModel.DEFAULT);
		assertTrue(best.isPresent());
		assertEquals(JoinPlan.Kind.SCAN, best.get().kind());
		assertEquals(42.0d, best.get().rows(), 1e-9);
		assertEquals(42.0d, best.get().cost(), 1e-9);
	}

	@Test
	void disconnectedGraphYieldsNoPlan() {
		PlanHypergraph planGraph = new PlanHypergraph();
		planGraph.addNode("A", 10);
		planGraph.addNode("B", 10);
		assertTrue(HypergraphOptimizer.bestPlan(planGraph, CostModel.DEFAULT).isEmpty(),
				"no Cartesian products: a disconnected graph has no full plan");
	}

	@Test
	void bushyPlanWinsWhenTwoSelectiveIslandsMeetInTheMiddle() {
		// Chain A -- B -- C -- D. A and D are huge, B and C small. The A-B and C-D joins are very selective while
		// the middle B-C edge multiplies freely, so every left-deep order materializes a huge intermediate before
		// the final join; the bushy plan (A⋈B) ⋈ (C⋈D) keeps both inputs of the top join tiny.
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 1_000_000);
		int b = planGraph.addNode("B", 1000);
		int c = planGraph.addNode("C", 1000);
		int d = planGraph.addNode("D", 1_000_000);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 1e-6d, "ab");
		planGraph.addJoinEdge(NodeSets.bit(b), NodeSets.bit(c), 1.0d, "bc");
		planGraph.addJoinEdge(NodeSets.bit(c), NodeSets.bit(d), 1e-6d, "cd");

		JoinPlan best = HypergraphOptimizer.bestPlan(planGraph, CostModel.DEFAULT).orElseThrow();

		assertFalse(best.isLeftDeep(), "expected a bushy winner but got " + best.describe(planGraph::nodeName));
		long ab = NodeSets.bit(a) | NodeSets.bit(b);
		long cd = NodeSets.bit(c) | NodeSets.bit(d);
		assertTrue(Set.of(ab, cd).equals(Set.of(best.left().nodes(), best.right().nodes())),
				"top join must combine {A,B} with {C,D}: " + best.describe(planGraph::nodeName));
		assertEquals(1_000_000.0d, best.rows(), 1e-3);
	}

	@Test
	void chainOfThreePicksTheCheapOrder() {
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 1000);
		int b = planGraph.addNode("B", 1);
		int c = planGraph.addNode("C", 1000);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 0.001d, "ab");
		planGraph.addJoinEdge(NodeSets.bit(b), NodeSets.bit(c), 0.001d, "bc");

		JoinPlan best = HypergraphOptimizer.bestPlan(planGraph, CostModel.DEFAULT).orElseThrow();
		assertEquals(1.0d, best.rows(), 1e-9);
		// The bottom join must involve B (either side); starting from the A-C Cartesian product is impossible.
		JoinPlan bottom = best.left().kind() == JoinPlan.Kind.SCAN ? best.right() : best.left();
		assertTrue(NodeSets.overlaps(bottom.nodes(), NodeSets.bit(b)),
				"the first join must use the tiny middle table: " + best.describe(planGraph::nodeName));
	}

	@Test
	void hyperedgeForcesTheGatedSideToAssembleFirst() {
		// A -- B simple edge; {A,B} -- {C} hyperedge: C may only join once A and B are both present.
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 100);
		int b = planGraph.addNode("B", 100);
		int c = planGraph.addNode("C", 100);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 0.01d, "ab");
		planGraph.addJoinEdge(NodeSets.bit(a) | NodeSets.bit(b), NodeSets.bit(c), 0.01d, "ab~c");

		JoinPlan best = HypergraphOptimizer.bestPlan(planGraph, CostModel.DEFAULT).orElseThrow();
		assertEquals(NodeSets.bit(a) | NodeSets.bit(b),
				NodeSets.isSingleton(best.left().nodes()) ? best.right().nodes() : best.left().nodes(),
				"one side of the top join must be exactly {A,B}: " + best.describe(planGraph::nodeName));
		assertEquals(100 * 100 * 100 * 0.01d * 0.01d, best.rows(), 1e-6);
	}

	@Test
	void pairBudgetAbortYieldsEmpty() {
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 10);
		int b = planGraph.addNode("B", 10);
		int c = planGraph.addNode("C", 10);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 0.1d, "ab");
		planGraph.addJoinEdge(NodeSets.bit(b), NodeSets.bit(c), 0.1d, "bc");
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(c), 0.1d, "ac");
		assertTrue(HypergraphOptimizer.bestPlan(planGraph, CostModel.DEFAULT, 1).isEmpty());
	}

	@Test
	void dotRenderingIsAvailableForTraces() {
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 10);
		int b = planGraph.addNode("B", 10);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 0.5d, "ab");
		String dot = planGraph.toDot();
		assertTrue(dot.contains("A -- B;"), dot);
	}
}
